const raw = $input.first().json.text || $input.first().json.response || '';
const minuta_id = $('Preparar Prompt').first().json.minuta_id;

let analise;
try {
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    analise = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('No JSON found');
  }
} catch (e) {
  analise = {
    score: 50,
    resumo: 'Analise parcial - resposta nao estruturada. ' + raw.substring(0, 200),
    riscos: [{ titulo: 'Erro na analise', severidade: 'medio', descricao: 'O modelo retornou resposta nao estruturada. Tente novamente.', clausula_ref: '', sugestao_mitigacao: 'Reprocessar' }],
    sugestoes: [],
    clausulas_analisadas: [],
    conformidade: {}
  };
}

if (typeof analise.score !== 'number' || analise.score < 0 || analise.score > 100) analise.score = 50;

return { json: { minuta_id, analise, analyzed_at: new Date().toISOString() } };
